var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-12: <color=#ffd34c>【부록-002】 영상 기록</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-12：<color=#ffd34c>【付録-002】 映像記録</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-12: <color=#ffd34c>【Appendix-002】 Video Record</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-12: <color=#ffd34c>【附錄-002】 影像記錄</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"어서 오세요~ 손님~","JPN":"いらっしゃいませ～お客様～♪","ENG":"Welcome!","TWN":"歡迎光臨！您好～"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"풍선껌부터 미사일까지! 세기말 편의점 아포칼립스에 잘 오셨습니다!","JPN":"チューインガムからミサイルまで！世紀末コンビニ、アポカリプスへようこそ～♪","ENG":"From bubble gum to missiles! You can find anything at Apocalypse, the apocalyptic convenience store!","TWN":"從口香糖到導彈！歡迎來到世紀末便利商店“啟示錄”！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"와아......","JPN":"わぁ……","ENG":"Wow.","TWN":"哇……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"여, 여기가 직영점이야? 언더그라운드 때 다니던 데랑은 전혀 달라......","JPN":"こ、ここって直営店ですか？　アンダーグラウンド時代に通ってた支店とはまるで違うような……","ENG":"I-is this a company-operated store? It's completely different from the one we used to go in the Underground.","TWN":"這、這裡是直營店嗎？和以前秘密活動時代去的地方完全不一樣……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"야, 언제까지 촌뜨기처럼 두리번거리고 있을 거야?","JPN":"こら、いつまでキョロキョロしてんだ？田舎者に見えるだろうが。","ENG":"Hey, stop looking around like a bum!","TWN":"喂，妳要像個鄉巴佬一樣，東張西望到什麼時候啊？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"괜찮으니까 마음껏 둘러 보세요.","JPN":"どうぞ、心行くまでご覧になってくださいね。","ENG":"It's fine, please take your time to look around.","TWN":"沒有關係，請隨便看看吧。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"벽지 색깔이나 인테리어는 촌스럽지만 물건이라면 많이 진열되어 있으니까요.","JPN":"壁紙の色とかインテリアはダサいですけど、品物は豊富に用意してありますので～♪","ENG":"The interior design may be tacky, but we have plenty of products on display.","TWN":"雖然壁紙的顏色和裝飾都很土，但有各式各樣的商品陳列在這裡。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"됐고 그런 거보다 총 없어? 총?","JPN":"そんなことより、銃はねえのか？銃は！","ENG":"Do you have any guns? Like, big ones?","TWN":"好啦好啦，這裡有賣槍嗎？槍？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"정식 라이선스도 받았겠다, 기념으로 멋진 녀석들로 장만하고 싶은데.","JPN":"正式ライセンスも貰ったところだし、記念にイカした奴を揃えたくてな。","ENG":"Now that I have an official license, I'd like to get some awesome ones to celebrate.","TWN":"正式的許可證也拿到了，我想買幾個帥氣的傢伙當做紀念。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"정말요?","JPN":"まあ～ほんとうですか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"뭔진 모르겠지만 축하드려요! 와아~!","JPN":"何だかわかりませんけど、おめでとうございます！わ～い♪","ENG":"I don't know what you're talking about, but congratulations! Wow!","TWN":"雖然不知道怎麼回事，但是恭喜妳！哇～！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"저어, 유진아. 우린 막 입사해서 라이선스는 아직 멀었는데......","JPN":"あの、シロコ。私たちまだ入社したてだよ？　ライセンス取得は当分先のはず……","ENG":"Um, Eujin. We just joined the company. It's going to take a while for us to get our licenses.","TWN":"那個，劉珍。我們才剛入職沒多久，要拿到許可證還要很久很久……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"누가 그래? 라이선스 따는 건 금방이야.","JPN":"んなこと誰が言ったんだ？ライセンスなんざすぐに取れるに決まってんだろ。","ENG":"Says who? I'll get mine in no time.","TWN":"誰說的？我們很快會拿到許可證的。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그, 그렇게 쉽진 않을 것 같은데......","JPN":"そ、そんなに簡単とは思えないけど……","ENG":"I-I don't think it will be that easy...","TWN":"我、我覺得沒有那麼容易……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"너 대장 말 못 들었냐?","JPN":"お前、隊長の話聞いてなかったのか？","ENG":"Didn't you hear what Cap said?","TWN":"妳沒聽到隊長說的話嗎？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"우린 강해. 강한 사람이 인정 받는 건 당연한 거라고.","JPN":"俺たちは強えだろ？そんで、強え奴は認められる。当然のことだろ。","ENG":"We're strong. It's natural for the strong to gain respect.","TWN":"我們很強，強者獲得認同是當然的。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"지난번엔 그 그림자인가 하는 기분 나쁜 녀석 때문에 대장이 고생했지만......","JPN":"この前はあのシャドウとかいう気色の悪い奴のせいで、隊長が苦労してたけどよ……","ENG":"Last time, Cap had to take a few hard knocks because of that stupid Shadow or something...","TWN":"雖然上次，隊長因為那個噁爛的暗影混蛋吃了不少苦頭……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"두고 봐! 언젠가 그 멍멍이 소대 녀석들 콧대를 납작하게 만들어 줄 테니까!","JPN":"今に見てろ！いつかあのワンコ小隊の奴らの鼻っ柱をへし折ってやっからな！","ENG":"But you just watch! We're going to put down that Doggie Squad one day!","TWN":"但等著瞧！我會重挫那個野狗小隊的銳氣的。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"하, 아하하...... 오늘도 기운이 넘치는구나...... 좋겠다, 유진이는......","JPN":"あ、あはは……今日もシロコは元気だね……何だか羨ましいよ……","ENG":"Hah, hah hah... You're lively as ever... I envy you, Eujin...","TWN":"啊、啊哈哈……今天也是活力充沛呢……真羡慕妳啊，劉珍……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그래서 총은 어디 있어? 저기 진열된 게 전부야?","JPN":"で、銃はどこだ？あそこに並んでるので全部か？","ENG":"So where are the guns? Is that all you've got?","TWN":"所以槍在哪裡？那邊放著的就是全部嗎？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"물론 아니죠, 손님. 저희 가게엔 별난 취향을 가진 분들이 많이 찾아 주시거든요.","JPN":"もちろん違いますよ、お客様。当店には変わった趣味をお持ちの方もたくさんいらっしゃいますもの。","ENG":"Of course not. We have a lot of customers with unique preferences.","TWN":"當然不是了，客人。本店經常會有很多有著奇怪愛好的客人光顧。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"그래서 정말 특별한 상품들은 단속 안 걸리게 꼭꼭 숨겨 놓고 있어요.","JPN":"だから、本当にスペシャルなラインナップは、摘発されることがないように隠してあるんです。","ENG":"We keep our special items hidden so that we won't get busted.","TWN":"所以我們都會把真正特殊的商品好好藏起來，以免被取締。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"특별한 상품? 진짜?","JPN":"スペシャルなラインナップ？そんなもんがあるのか？","ENG":"Special items? Really?","TWN":"特殊的商品？真的？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"저, 단속에 걸릴 만한 물건이면 위험하지 않을까......?","JPN":"ええと、摘発されるような商品って、危ないものなんじゃ……？","ENG":"Um, wouldn't it be dangerous to buy items that are prohibited by law?","TWN":"那個，如果是會被取締的東西、應該很危險吧……？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"내가 그런 거에 걸릴 것 같아? 빨리 보여 주기나 해!","JPN":"俺はしょっぴかれるようなヘマはしねえ！さっそく見せてもらうぜ！","ENG":"Do you really think I'll get caught? Bring them out already!","TWN":"我會被這種話騙嗎？快點讓我看看！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"손님은 권총을 쓰시죠? 그래서 여기 이렇게, 짜잔!","JPN":"お客様は拳銃をお使いですよね？でしたらこの通り、じゃじゃ～ん♪","ENG":"You use a handgun I presume? So I brought these, ta-da!","TWN":"客人用的是手槍吧？那這些怎麼樣，鏘鏘！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"오오...... 처음 보는 것도 많은데......","JPN":"おおぉ……見たことないのも結構あるな……","ENG":"Ooh... There are so many guns that I've never seen before.","TWN":"哦哦……好多都是第一次看到……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이거 혹시 쓸 수 있나 시험해 봐도 돼?","JPN":"これ、ちゃんと使えるか試させてもらってもいいか？","ENG":"Can I test them out?","TWN":"可以試一下這個嗎？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"물론이죠. 사격장은 저쪽에 마련되어 있답니다.","JPN":"もちろんです。射撃場はあちらに用意してあります。","ENG":"Of course. We have a shooting range right over there.","TWN":"當然了，射擊場請往這邊走。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"저...... 점원님. 죄송한데, 유진이를 말려야 할 것 같아요.","JPN":"て、店員さん。お心遣いは嬉しいですけど、シロコを止めた方が……","ENG":"Um... Excuse me. But I think we have to stop Eujin.","TWN":"那個……店員小姐，非常抱歉，但我覺得需要阻止一下劉珍了。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"무슨 말씀이세요?","JPN":"まあ、何をおっしゃるんですか？","ENG":"What do you mean?","TWN":"您在說什麼啊？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"저희 아포칼립스는 모든 손님들께 최상의 서비스를 제공하고 있다고요.","JPN":"アポカリプスは、すべてのお客様に最上のサービスを提供するのがモットーなんです。","ENG":"Here at Apocalypse, we are always obligated to provide the best service to our customers.","TWN":"我們“啟示錄”會為所有客人提供最好的服務。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"사격 테스트 정도는 언제든 환영이에요.","JPN":"射撃テストの一つや二つ、いつでも歓迎ですよ♪","ENG":"You are all welcome to use the shooting range any time.","TWN":"隨時都歡迎進行射擊測試。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"아, 아뇨. 그런 게 아니라 유진이는......","JPN":"い、いえ。そういうことじゃなくて、シロコは……","ENG":"N-no. That's not what I meant. Eujin...","TWN":"啊，不是，不是那個意思，因為劉珍她……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"에이, 부서졌잖아. 너무 약한데?","JPN":"何だよ、壊れちまった。ヤワすぎなんじゃねえのか？","ENG":"Aw, it broke. This one is too weak.","TWN":"喂，這不是碎掉了嗎，這也太容易壞了吧？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"총을 좀 험하게 다루는 편이라서요......","JPN":"銃の扱い方が少々乱暴ですから……","ENG":"She handles her guns very roughly...","TWN":"對待槍械有點粗暴……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"쳇, 역시 던져도 멀쩡한 건 그 할아범이 만든 것밖에 없나.","JPN":"チッ、やっぱりブン投げても何ともねえのはあのジジイの造った奴だけか。","ENG":"Tsk, I guess that old man's guns are the only ones that can be thrown without breaking.","TWN":"切，果然扔了也不會壞的，就只有那個老頭做的啊。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"이, 이봐요! 총은 집어 던지는 게 아니라 쏘는 거라고요!","JPN":"ちょ、ちょっと！銃は投げるんじゃなくて撃つものでしょう？","ENG":"H-hey! You're supposed to shoot guns, not throw them!","TWN":"喂，喂！槍不是用來丟的，是用來射的啊！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"하지만 총알이 떨어졌는걸?","JPN":"でも、弾切れになったら投げるしかねえよな？","ENG":"But I ran out of bullets.","TWN":"但是沒子彈了啊。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"탄창을 바꾸면 되죠!","JPN":"普通なら弾倉を取り替えます！","ENG":"Then you're supposed to reload!","TWN":"換彈匣就好了啊！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그럴 틈이 어딨어? 여유 부리다가 한 놈이라도 놓치면 어쩌라고?","JPN":"そんな暇ねえって！のんきに弾倉なんか込めてたらな、取り逃すのがオチだぞ！","ENG":"I don't have time for that. What if one of them gets away while I'm taking my sweet time?","TWN":"哪有那種閒工夫？要是在換彈匣的時候，敵人跑掉了怎麼辦？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"아, 이 녀석은 좀 튼튼하게 생겼는데? 좋았어!","JPN":"おっ、こいつは結構頑丈そうな見た目してんな。よーし、行くぞ！","ENG":"Oh, this one looks pretty sturdy. Alright!","TWN":"啊，這把看起來挺堅固的。很好！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"역시 망가졌네.","JPN":"あ、やっぱ壊れちまうのか。","ENG":"Aw, it broke again.","TWN":"果然壞掉了。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"뭐 하는 거에요, 당신!","JPN":"ふ、ふざけるのも大概にしてくださいー！","ENG":"What are you doing?!","TWN":"妳在做什麼啊！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"권총을 몽둥이처럼 휘두르는데 당연히 망가지죠!","JPN":"拳銃をバールのようにブンブン振り回してたら、壊れて当然じゃないですか！","ENG":"It's obviously going to break if you swing it like a bat!","TWN":"把手槍當棍子來揮，當然會壞掉啊！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"죄송해요. 정말 죄송합니다. 배상은 어떻게든......","JPN":"ごめんなさい。本当にごめんなさい。何とかして弁償を……","ENG":"We're sorry. We're really sorry. We'll pay for them...","TWN":"對不起，真是對不起。我們會想辦法賠償的……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"유, 유진아. 너도 어서 사과 드려. 장사하시는 데 폐를 끼쳤잖아.","JPN":"シ、シロコも早く謝って。お店に迷惑をかけたんだから。","ENG":"Eu-Eujin. You need to apologize, too. We're disrupting her business.","TWN":"劉、劉珍，妳也快來道歉。這不是給店家添麻煩了嗎？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"어, 어? 그랬어?","JPN":"え、あれ？そうなのか？","ENG":"Uh, oh? We are?","TWN":"呃、呃？是嗎？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"저, 저기. 미안. 난 그냥 미사일까지 판다기에 내 총보다 튼튼한 것도 있는 줄 알고......","JPN":"わ、悪いな。ミサイルまで売ってるって言ってたからよ。てっきり俺の銃よりも頑丈な武器もあるかと思ってさ……","ENG":"U-um. Sorry. Since you sell missiles, I figured you'd have some guns that are stronger than mine.","TWN":"那、那個，抱歉！我聽說這裡連導彈都賣，還以為會比我的槍堅固的呢……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그 정도 상품이 없을 거라는 건 몰랐어...... 다음엔 조심할게......","JPN":"そんなもん売ってるはずないのにな……次からは気をつけるぜ……","ENG":"I didn't realize there would be no such products... I'll try to be more careful next time...","TWN":"沒想到沒有那種商品……下次我會注意的……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"......방금 뭐라고 하셨어요?","JPN":"……今、何とおっしゃいましたか？","ENG":"What did you just say?","TWN":"……妳剛才說什麼？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"네?","JPN":"えっ？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"이 점포에서 장사 못 해 먹겠다고 그만둔 전 직원 분에게 배웠어요.","JPN":"こんな立地じゃ商売はできないと言い残して辞めて行った前任者に教わったんです。","ENG":"I learned from the former employee who quit this job because he couldn't take it any longer.","TWN":"曾經有一個沒辦法繼續在這裡工作的離職員工告訴我。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"저희 아포칼립스의 신조는 <color=#ffd34c>손님이 원하는 상품은 무엇이든 준비해 놓는다</color>!","JPN":"アポカリプスチェーンの信条は、<color=#ffd34c>お客様が希望する商品は何でも用意しておくこと</color>！","ENG":"That our creed here at Apocalypse is that <color=#ffd34c>we prepare any product that the customer desires</color>!","TWN":"本店“啟示錄”的宗旨是<color=#ffd34c>準備客人想要的任何商品</color>！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"방금 그 발언은 프랜차이즈에 대한 도전장이나 마찬가지에요.","JPN":"今の発言は、当フランチャイズへの挑戦状に他なりません。","ENG":"Your previous statement is a challenge towards our franchise.","TWN":"您剛剛的發言等同於對這間加盟店的挑戰書。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"저, 저기요, 점원님? 그런 식으로 말씀하시면 유진이까지......","JPN":"え、ええっと、店員さん？　そんな言い方をされてしまったら、シロコの方も……","ENG":"U-uh, excuse me? If you say it like that, Eujin is going to...","TWN":"呃，那個……店員小姐？用那種語氣說的話，連劉珍都會……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"오, 뭐야? 지금 나랑 한 판 붙어 보잔 소리지?","JPN":"おお、何だ何だ？俺と張り合おうって言ってんのか？","ENG":"Oh, what's that? You're looking for a fight?","TWN":"啥，什麼？妳現在是想跟我較量一場嗎？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"좋아! 질 수 없지! 어디 내가 써도 멀쩡한 게 있나 한 번 보자고!","JPN":"よし！それなら負けてらんねえぜ！俺が使っても何ともねえ武器が本当にあるのかどうか、勝負だ！","ENG":"Alright! I got this! Let's see if you can bring out something that I can use properly!","TWN":"好啊！我是不會輸的！讓我看看被我用過也不會出事的東西吧！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"후회라면 지금 해 두세요.","JPN":"後で後悔しても知りませんからね。","ENG":"This will be your last chance.","TWN":"要後悔就趁現在吧。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"저희 지점의 상품 다양성 앞에 곧 두 손 두 발 다 드실 테니까요.","JPN":"あなたは当店の商品バリエーションの豊富さの前に、ひれ伏すことになるでしょう。","ENG":"You will be overwhelmed by our shop's diverse inventory.","TWN":"在本分店的商品多樣性面前，妳很快就會舉起雙手雙腳投降的。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"웃기시네! 오늘 간판 내릴 준비나 하고 있어!","JPN":"笑わせてくれるぜ！今日付けで閉店する用意でもしてろよな！","ENG":"Hah! I'll put you out of business today!","TWN":"真是好笑！準備好被我砸招牌吧！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"흑흑...... 대장...... 도와 줘......!","JPN":"ううぅぅ……隊長……、助けて……！","ENG":"*Sob* Cap... Help!","TWN":"嗚嗚……隊長……救救我……！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이런 경위로, 아포칼립스 본사로부터 배상금이 청구되었습니다.","JPN":"こういった経緯から、アポカリプス本社より賠償金の請求が来ております。","ENG":"That is why we received an invoice for damages from Apocalypse HQ.","TWN":"由於這樣的經過，“啟示錄”總部發來了賠款申請。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"쌍방 과실로 처리됐다지만, 서윤 양이 사태를 파악하고 도착하기 전까지 300 자루를 해먹었더군요.","JPN":"双方に過失があるという判断になったとはいえ、アオイ・シズカが状況を知り駆けつけるまで、優に300丁もの銃器類を損壊させたとのことです。","ENG":"Although both parties were responsible, by the time Seo Yoon arrived at the scene, Eujin had already broken 300 guns.","TWN":"雖然是以雙方過失來處理，但在徐芸小姐搞清楚狀況，到達現場之前，已經弄壞300支了。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......어쩐다. 자네 고충에 공감이 가기 시작하는데.","JPN":"……まいったな。私にも君の苦労がわかる気がしてきたぞ。","ENG":"Good lord. I'm starting to relate to your problems.","TWN":"……我開始能理解你的痛苦了。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};